 * @param {string} archivePath - Path to the zip file
 * @param {string} destDir - Destination directory
 * @returns {Promise<void>}
 */
function extractZip(archivePath, destDir) {
  return new Promise((resolve, reject) => {
    const absDest = path.resolve(destDir);
    const absArchive = path.resolve(archivePath);

    execFile('powershell', [
      '-NoProfile',
      '-Command',
      `[System.IO.Compression.ZipFile]::ExtractToDirectory('${absArchive.replace(/'/g, "''")}', '${absDest.replace(/'/g, "''")}');`
    ], { timeout: 30000 }, (err) => {
      if (err) reject(new Error(`PowerShell zip extraction failed: ${err.message}`));
      else resolve();
    });
  });
}

